#!/usr/bin/env python3
"""
ChiMigo Batch Patch Script
Run this from your chimigo-books repo root directory.
Replaces 🐼 (and any extra emojis) with the ChiMigo logo image
across ALL practice.html files in p1s*b* and p2s*b* folders.
"""
import os, re

LOGO_IMG = '''
<img src="data:image/jpeg;base64," style="height:80px;width:auto;display:block;margin:0 auto 8px auto;" alt="ChiMigo">
'''

def patch_file(path):
    with open(path, encoding='utf-8') as f:
        c = f.read()
    
    original = c
    
    # 1. Replace modal emoji div: any emoji(s) → logo image
    c = re.sub(
        r'(<div style="font-size:2\.5rem;">)[^<]*(</div>)',
        r'\1' + LOGO_IMG + r'\2',
        c
    )
    
    # 2. Strip any stray emojis left outside the logo tag
    # Common themed emojis that sneak into headers/titles
    emoji_pattern = re.compile(
        u'[\U0001F300-\U0001F9FF'
        u'\U00002600-\U000027BF'
        u'\U0001FA00-\U0001FA9F]+',
        re.UNICODE
    )
    # Only strip outside of base64 data (safe: base64 has no emoji chars)
    c = emoji_pattern.sub('', c)
    
    if c != original:
        with open(path, 'w', encoding='utf-8') as f:
            f.write(c)
        return True
    return False

patched = 0
skipped = 0
for folder in sorted(os.listdir('.')):
    if not re.match(r'p[12]s[123]b[1-8]', folder):
        continue
    practice = os.path.join(folder, 'practice.html')
    if not os.path.exists(practice):
        skipped += 1
        continue
    if patch_file(practice):
        print(f'✅ Patched: {practice}')
        patched += 1
    else:
        print(f'⏭  No change: {practice}')

print(f'\nDone — {patched} files patched, {skipped} folders had no practice.html')
